var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어...... 제가 카운터라고요?","JPN":"えっ……私がカウンター？","ENG":"Uh... I'm a Counter?","TWN":"呃……你說我是制裁者？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"그래. 어제 관리국에서 공문이 날아왔더구나.","JPN":"そうだ。昨日管理局から公文書が届いてな。","ENG":"Yes. The official document came in from the Administration yesterday.","TWN":"對，昨天管理局寄了份公文。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"네가 어제 사람을 구한 영상을 봤는데 100% 틀림없대.","JPN":"昨日お前が人を救った映像を見たそうで、100％間違いないって言ってるぞ。","ENG":"They are 100% sure after seeing the video of you saving that man yesterday.","TWN":"他們說看了妳昨天救人的影片，100%沒錯。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"워치도 가지고 있잖니?","JPN":"ウォッチも持っているだろう？","ENG":"You even have a Watch.","TWN":"妳不是也有能量環嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"이 시계요?","JPN":"あぁ、この時計ですか？","ENG":"This watch?","TWN":"這個手錶嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어디서 구했는진 잘 기억이 안 나지만, 저는 그렇게 비싼 건 산 적이 없는데.","JPN":"どこで手に入れたのかは覚えてないけど、こんな高価そうな物……買った記憶ないのに……","ENG":"I'm not sure where I got it, but I've never bought something that expensive.","TWN":"我不記得我是怎麼拿到這隻手錶的，但我從來沒買過很貴的東西欸。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"......원래 워치란 건 자기도 출처를 모르는 경우가 많다고 하더구나.","JPN":"……元々ウォッチというのは、どこで\\n手に入れたのかわからない場合が多いらしい。","ENG":"Counters usually don't realize where their Watches came from.","TWN":"……說到能量環，本來就有很多人不知道自己是怎麼拿到的。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"어쨌든 관리국에서 틀린 말을 할 리는 없을 테니까.","JPN":"とにかく、管理局が間違ったことを言うわけがないからな。","ENG":"Anyway, the Administration has no reason to lie to you.","TWN":"總而言之，管理局是不會認錯的。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"전도유망한 카운터가 된 걸 축하해 줘야겠지? 선생님도 조금은 질투 나는걸?","JPN":"前途有望なカウンターになったことを\\n祝うべきだろう。先生も羨ましいよ。","ENG":"I suppose a celebration is in order for our promising new Counter? I'm a little jealous myself.","TWN":"那我該恭喜妳成為前途光明的制裁者吧？老師也有點嫉妒妳呢。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하지만 전 용병이 되거나 싸우는 건 별로 관심이 없는 걸요!","JPN":"でも私は傭兵になったり、\\n戦うのはあまり興味がないんです！","ENG":"But I have no interest in becoming a mercenary or fighting!","TWN":"但是我當傭兵和戰鬥一點興趣都沒有啊！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"꼭 이면세계에 가서 침식체와 싸우는 게 아니더라도, 카운터를 원하는 직장은 많아.","JPN":"裏世界に行って侵食体と戦うのでは\\nなくても、カウンターを欲しがる企業は多いからな。","ENG":"Even if you don't go to fight C.O. in the Counterside, there are a lot of jobs that require Counters.","TWN":"就算不去異界和侵蝕體作戰，想招聘制裁者的公司也很多。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"애초에 비전투 능력자들은 그런 일에 투입되지도 않고.","JPN":"そもそも、非戦闘型能力者たちは\\nそういう仕事にはつかされないだろう。","ENG":"And Counters with no combat abilities are not deployed into combat.","TWN":"而且非戰鬥能力者也不會被派到現場的。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"진로는 다양하니까 벌써부터 너무 걱정할 필요는 없어.","JPN":"進路は様々だ。今から心配する必要はないぞ。","ENG":"There are a lot of options for you. You don't have to stress about it already.","TWN":"出路有很多種，所以不用想那麼多。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그렇군요......","JPN":"……そうですか。","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"저, 그럼 앞으로 어떻게 되는 건가요?","JPN":"そしたら、これから私はどうなるんですか？","ENG":"Then what should I do from now on?","TWN":"那我以後會怎麼樣啊？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"일단은...... 전학을 가게 될 거야.","JPN":"ひとまず……転校することになるだろう。","ENG":"First of all, you will be transferred to a new school.","TWN":"首先……妳會轉學。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"네? 전학이요?","JPN":"えっ？　転校ですか？","ENG":"What? A transfer?","TWN":"咦？轉學？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"관리국 카운터 아카데미라고 들어봤니?","JPN":"管理局カウンターアカデミーというのは聞いたことがあるか？","ENG":"Have you heard of the Administration Counter Academy?","TWN":"妳有聽過管理局制裁者學院嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"규정상 워치를 가진 미성년자는 아카데미 교육을 이수하게 되어 있거든.","JPN":"規定上、ウォッチを持つ未成年者たちは\\nアカデミー教育を履修することになっているんだ。","ENG":"According to the regulations, all minors with a Watch are to complete their education at the Academy.","TWN":"按照規定，持有能量環的未成年者，必須到學院的接受教育。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"정식으로 전학 명령이 올 때까지는 시간이 좀 걸릴 테니까 그때까지 친구들이랑 인사라도 하고 있으렴.","JPN":"正式な転校命令が下されるまでは、少し時間が\\nかかるだろうから、それまでに友達に挨拶しておくといい。","ENG":"It will take some time until you're officially transferred. You should say goodbye to your friends until then.","TWN":"收到正式的轉學通知前需要一點時間。在那之前，妳就先跟同學們道別吧。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"......알겠습니다. 선생님.","JPN":"……わかりました。","ENG":"Okay. I will.","TWN":"……好的，老師。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"호진아!","JPN":"マユミ！","ENG":"Hojin!","TWN":"鎬眞！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어, 반장? 무슨 일이야......?","JPN":"あっ、委員長。どうかしたの……？","ENG":"Oh, hey. What's up?","TWN":"嗯，班長？什麼事啊……？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"읍!!","JPN":"うっ！","ENG":"Oof!","TWN":"呃！！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"역시 넌 카운터였어! 내 눈이 틀리지 않았다니까!","JPN":"やっぱりカウンターだったんだね！\\n私の目に狂いはなかった！","ENG":"You're a Counter! I knew my eyes didn't deceive me!","TWN":"妳果然是制裁者！我果然沒有看錯！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"저, 저기, 너무 끌어안아서 숨 막혀. 반장.","JPN":"ちょっ、ちょっと委員長、苦しいよ。","ENG":"U-uh, you're hugging me too hard. I can't breathe. Hello?","TWN":"那、那個……妳抱得太緊，我沒辦法呼吸了，班長。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"앗, 미안해. 호진이가 출세를 하니 나도 기뻐서 그만.","JPN":"あっ、ごめん。マユミの出世がすごく嬉しくてつい。","ENG":"Ah, sorry. I was just so happy for your success, Hojin.","TWN":"啊，抱歉。因為鎬眞能夠出人頭地，我實在太高興了。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"헤헤......","JPN":"へへ……","ENG":"Heh...","TWN":"嘿嘿……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그런데 내가 카운터인 줄 알고 있었다니...... 그게 무슨 소리야?","JPN":"でもやっぱりカウンターだったんだねって……どういう意味？","ENG":"But you knew I was a Counter? How?","TWN":"話說回來，你說早知道我是制裁者了……那是什麼意思啊？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"난 전혀 몰랐는데.","JPN":"私は全然気付かなかったのに。","ENG":"I had no idea myself.","TWN":"我就完全不知道耶。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"우리 반에서 그걸 눈치 못 챈 사람은 너밖에 없었을걸?","JPN":"このクラスで気づいてないの、マユミだけだと思うよ？","ENG":"You were probably the only one in our class who didn't notice.","TWN":"我們班上沒發現這件事的，恐怕就只有妳吧？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"아무것도 모르는 사람도 너랑 잠깐만 같이 지내다 보면 둘 중 하나는 확실하단 걸 알게 되지.","JPN":"何も知らない人だって少しマユミの傍にいれば、\\n二つのうちどっちかだなって思うはず。","ENG":"Even complete strangers will realize one or the two things once they spend some time with you.","TWN":"就算是什麼都不知道的人，只要和妳相處一段時間，遲早都會知道妳是其中一個制裁者。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"네가 비범한 초능력자거나, 아니면......","JPN":"あなたが特別な力を持つ超能力者か、もしくは……","ENG":"That either you're an unusual psychic...","TWN":"妳不是有非凡的超能力沉睡在體內，就是……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"세상이 조호진을 중심으로 돌아가고 있거나.","JPN":"この世界はイトウ・マユミを中心に回っているか。","ENG":"Or that the world revolves around Cho Hojin.","TWN":"世界是繞著趙鎬眞轉的。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으응? 그것도 무슨 말인지 잘 모르겠어.","JPN":"えっ？　意味がわからないよ。","ENG":"Hmm? I have no idea what you mean by that.","TWN":"嗯？我不懂這是什麼意思耶。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"모르면 모르는 대로 있는 것도 괜찮아. 그런 순수함이 네 매력이니까.","JPN":"わからなくても大丈夫だよ。その純粋さが\\nマユミの魅力でもあるんだから。","ENG":"It's okay if you don't realize it yourself. That sense of purity is what makes you special.","TWN":"不懂就不懂吧，單純就是妳的魅力啊。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"그보다 선생님이 불러서 뭐라고 하신 거야? 이제 어떻게 된대?","JPN":"それより、先生から何て言われたの？\\nこれからどうなるか聞いた？","ENG":"So what did the teacher want with you? What's going to happen next?","TWN":"不說這個了，老師跟妳說了什麼？妳以後會怎麼樣？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어, 그러니까...... 전학을......","JPN":"あーえっと……転校かな……","ENG":"Uh, about that... I'm transferring...","TWN":"呃，所以說那個……要轉學……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"관리국 카운터 아카데미로 전학을 가게 된다고 했어.","JPN":"管理局カウンターアカデミーに転校することになるって言われた。","ENG":"I'm going to be transferred to the Administration Counter Academy.","TWN":"她跟我說我會轉到管理局制裁者學院。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"아...... 그렇구나.","JPN":"あぁ……そうなんだ。","ENG":"Ah... I see.","TWN":"啊……這樣啊。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"다, 당장 가는 건 아니니까 괜찮아.","JPN":"で、でも！　今すぐじゃないから。","ENG":"I-I'm not leaving right away, so it's okay.","TWN":"不、不是馬上就要去，所以不要緊啦。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"......응, 작별인사 할 시간은 충분하겠네.","JPN":"……うん。みんなとお別れする時間くらいはあるよね？","ENG":"Yeah, we'll have plenty of time to say goodbye.","TWN":"……嗯，道別的時間也很夠吧。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 그럼 우리 호진이의 새출발을 위해 학급파티를 기획해야겠는걸?","JPN":"仕方ないよ。そしたら、マユミの新しい門出を\\n祝ってクラスでパーティーしないと！","ENG":"We can't do anything about that. But what we can do is have a big class party for Hojin's new beginning!","TWN":"沒辦法了。那為了祝福鎬眞新的旅程，我們要不要辦個班級同樂會？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하, 학급파티?","JPN":"パ、パーティー？","ENG":"A c-class party?","TWN":"班、班級同樂會？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그렇게 거창한 걸 준비할 필요는 없어!","JPN":"そんなの準備しなくていいよ！","ENG":"You don't have to do that for me!","TWN":"不需要這樣大費周章地準備啦！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"애초에 내가 전학을 가든 말든 관심 없는 애들도 많을 거고.","JPN":"そもそも、私が転校しようがしまいが\\n興味ない子たちの方が多いと思うし。","ENG":"I mean, most people are probably not interested in whether I get transferred or not.","TWN":"有很多同學都不會關心我轉不轉學的事情的。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"무슨 소리야? 애들이 다들 널 얼마나 좋아하는데?","JPN":"何言ってるの？　みんな、マユミのこと大好きなんだよ？","ENG":"What do you mean? Don't you know how much everyone likes you?","TWN":"妳在說什麼？大家都很喜歡妳啊。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"......정말?","JPN":"……本当に？","ENG":"Really?","TWN":"……真的嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"그럼! 우리 반 행운의 여신님이 전학을 가는데, 그 정도 송별회도 안 했다간 난 바로 반장 자리에서 쫓겨날 걸?","JPN":"もちろん！　うちのクラスの幸運の女神が\\n転校しちゃうのに、送別会もやらないなんて委員長失格でしょ？","ENG":"Yeah! I'll probably lose my job as class president if I don't plan a farewell party for our Goddess of Fortune!","TWN":"那當然了！我們班上的幸運女神要轉學了，要是我不幫妳辦個送別會的話，我這個班長就要被趕下台了吧？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"해, 행운의 여신? 혹시 이거 놀리는 거야?","JPN":"こ、幸運の女神？　まさかからかってるの？","ENG":"G-Goddess of Fortune? Are you making fun of me?","TWN":"幸、幸運的女神？妳是在取笑我嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"전~혀 아니거든? 넌 우리 반의 자랑이야.","JPN":"ぜ～んぜん？　マユミは私たちのクラスの自慢だもん！","ENG":"Not at all! You're the pride of our class.","TWN":"才沒有呢～妳是我們班的驕傲。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"그러니까 거기 가더라도 기죽지 말고 잘 지내라고.","JPN":"だから、転校しても元気に頑張ってね？","ENG":"So make sure to keep your chin up even when you go there.","TWN":"所以就算去了那裡，妳也不要感到沮喪，要保重喔。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"우리가 항상 응원하고 있을 테니까. 알겠지?","JPN":"私たちがいつも応援してるってこと、忘れないでほしいな。","ENG":"We'll always be cheering for you. Got it?","TWN":"我們會一直為妳加油的，好嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"......응!","JPN":"……うん！","ENG":"Yeah!","TWN":"……嗯！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"고마워, 친구야.","JPN":"ありがとう。","ENG":"Thanks, you're a good friend.","TWN":"謝謝妳，我的朋友。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CP_EXTRA_NULL_NULL","text":{"KOREA":"멋진 카운터가 돼서, 더 많은 사람들을 구해 주길 바랄게.","JPN":"立派なカウンターになって、たくさんの人を救ってね。","ENG":"I hope you become a great Counter, so you can help a lot of people.","TWN":"希望妳能成為一位偉大的制裁者，幫助更多的人。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};